if let Some(scheduled) = transaction.as_scheduled().map(|tx| tx.tx()) {
    receipt.origin_tx = Some(scheduled.origin_tx);
    receipt.call_id = Some(scheduled.call_id);
    receipt.index = Some(scheduled.index);
    receipt.initial_block = Some(scheduled.initial_block);
    receipt.frequency = Some(scheduled.frequency);
    receipt.max_block = Some(scheduled.expiry_block());
    receipt.ttl = Some(scheduled.ttl);
    receipt.caller = Some(scheduled.caller);
    receipt.gas = Some(scheduled.gas);
    receipt.max_fee_per_gas = Some(scheduled.max_fee_per_gas);
    receipt.max_priority_fee_per_gas = Some(scheduled.max_priority_fee_per_gas);
    receipt.value = Some(scheduled.value);
}
